using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class ShoppingListItemConfiguration : IEntityTypeConfiguration<ShoppingListItem>{public void Configure(EntityTypeBuilder<ShoppingListItem> builder){builder.ToTable("shopping_list_items");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("item_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.IngredientName).HasMaxLength(100).IsRequired();builder.Property(e => e.TotalAmount).HasColumnType("decimal(10,2)");builder.Property(e => e.Unit).HasMaxLength(30).IsRequired();builder.Property(e => e.Category).HasMaxLength(50);builder.Property(e => e.EstimatedCostMxn).HasColumnType("decimal(10,2)");builder.Property(e => e.SubstitutionReason).HasMaxLength(50);builder.HasOne(e => e.ShoppingList).WithMany(sl => sl.Items).HasForeignKey(e => e.ShoppingListId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.PurchasedByUser).WithMany().HasForeignKey(e => e.PurchasedByUserId);builder.HasOne(e => e.Ingredient).WithMany().HasForeignKey(e => e.IngredientId);builder.HasOne(e => e.StoreCategory).WithMany().HasForeignKey(e => e.StoreCategoryId);builder.HasOne(e => e.SubstitutedFrom).WithMany().HasForeignKey(e => e.SubstitutedFromId);}}
